Infraestrutura como codigo para database - TechCorp Brasil - ecommerce-migration:

**main.tf:**
```hcl
terraform {
  required_providers {
    oci = {
      source  = "oracle/oci"
      version = "~> 5.0"
    }
  }
}

provider "oci" {
  region = "sa-saopaulo-1"
}

resource "oci_database_autonomous_database" "main" {
  compartment_id = var.compartment_ocid
  display_name   = "database-production-000"

  # Configuracao especifica
  shape          = "VM.Standard.E4.Flex"

  tags = {
    project     = "TechCorp Brasil - ecommerce-migration"
    environment = "production"
    managed_by  = "terraform"
  }
}

variable "compartment_ocid" {
  type        = string
  description = "OCID do compartment production"
}

output "resource_id" {
  value = oci_database_autonomous_database.main.id
}
```

**variables.tf:**
```hcl
variable "compartment_ocid" {
  type        = string
  description = "OCID do compartment"
}

variable "region" {
  type        = string
  default     = "sa-saopaulo-1"
  description = "Regiao OCI"
}
```

**Deploy:**
```bash
terraform init
terraform plan -var="compartment_ocid=ocid1.database.us.5de7cb44f0260e9c24b201bd2a05ec68"
terraform apply -var="compartment_ocid=ocid1.database.us.5de7cb44f0260e9c24b201bd2a05ec68" -auto-approve
```

**Configuracao:**
- Compartment: `production`
- Region: `sa-saopaulo-1`
- Shape: `VM.Standard.E4.Flex`
- OCPUs: `1`
- Storage: `50 GB`

Documentacao: https://registry.terraform.io/providers/oracle/oci/latest/docs

